/* ECharts 5.4.3 本地替代版本 - 简化版 */
const echarts = {
  init: function(dom) {
    const chart = {
      dom: dom,
      option: {},
      setOption: function(option) {
        this.option = option;
        this.render();
      },
      render: function() {
        // 简化版渲染逻辑
        const canvas = document.createElement('canvas');
        canvas.width = this.dom.clientWidth;
        canvas.height = this.dom.clientHeight;
        this.dom.innerHTML = '';
        this.dom.appendChild(canvas);
        
        const ctx = canvas.getContext('2d');
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        
        // 绘制标题
        if (this.option.title) {
          ctx.font = '16px Arial';
          ctx.fillStyle = '#333';
          ctx.textAlign = 'center';
          ctx.fillText(this.option.title.text || '', canvas.width / 2, 30);
        }
        
        // 绘制饼图
        if (this.option.series && this.option.series[0] && this.option.series[0].type === 'pie') {
          const series = this.option.series[0];
          const data = series.data || [];
          const center = series.center || ['50%', '50%'];
          const radius = series.radius || '60%';
          
          const centerX = canvas.width * (parseInt(center[0]) / 100);
          const centerY = canvas.height * (parseInt(center[1]) / 100);
          const radiusValue = Math.min(centerX, centerY) * (parseInt(radius) / 100);
          
          let startAngle = -90;
          const total = data.reduce((sum, item) => sum + (item.value || 0), 0);
          
          data.forEach((item, index) => {
            const angle = (item.value / total) * 360;
            const endAngle = startAngle + angle;
            
            // 绘制扇形
            ctx.beginPath();
            ctx.moveTo(centerX, centerY);
            ctx.arc(centerX, centerY, radiusValue, startAngle * Math.PI / 180, endAngle * Math.PI / 180);
            ctx.closePath();
            
            // 使用颜色
            const color = series.itemStyle?.color || ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];
            ctx.fillStyle = color[index % color.length];
            ctx.fill();
            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 2;
            ctx.stroke();
            
            startAngle = endAngle;
          });
          
          // 绘制图例
          if (this.option.legend) {
            const legendData = this.option.legend.data || [];
            const color = series.itemStyle?.color || ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];
            
            legendData.forEach((item, index) => {
              ctx.fillStyle = color[index % color.length];
              ctx.fillRect(50, 80 + index * 25, 16, 16);
              
              ctx.fillStyle = '#333';
              ctx.font = '12px Arial';
              ctx.textAlign = 'left';
              ctx.fillText(item, 75, 92 + index * 25);
            });
          }
        }
      }
    };
    return chart;
  }
};
